/* 抽象クラスAnimalの定義 */
abstract class Animal {
    /* 抽象メソッドsoundの定義 */
    abstract void sound();
}

/* Animalクラスを継承したDogクラスの定義 */
class Dog extends Animal {
    /* soundメソッドの具体的な実装 */
    void sound() {
        System.out.println("Woof Woof!");
    }
}

/* Animalクラスを継承したCatクラスの定義 */
class Cat extends Animal {
    /* soundメソッドの具体的な実装 */
    void sound() {
        System.out.println("Meow Meow!");
    }
}

public class Main {
    public static void main(String[] args) {
        /* Dogクラスのインスタンスを生成 */
        Dog d = new Dog();
        /* Dogクラスのsoundメソッドを呼び出し */
        d.sound();
        /* 出力結果：Woof Woof! */

        /* Catクラスのインスタンスを生成 */
        Cat c = new Cat();
        /* Catクラスのsoundメソッドを呼び出し */
        c.sound();
        /* 出力結果：Meow Meow! */
    }
}

