        /* Bikeクラスのインスタンスを生成 */
        Bike b = new Bike();
        /* Bikeクラスのrunメソッドを呼び出し */
        b.run();
        /* 出力結果：Bike is running. */
    }
}

/* 抽象クラスAnimalの定義 */
abstract class Animal {
    /* Animalクラスのコンストラクタ */
    public Animal() {
        System.out.println("An animal has been created.");
    }

    /* 抽象メソッドsoundの定義 */
    abstract void sound();
}

/* Animalクラスを継承したDogクラスの定義 */
class Dog extends Animal {
    /* Dogクラスのコンストラクタ */
    public Dog() {
        /* スーパークラスのコンストラクタを呼び出す */
        super();
        System.out.println("A dog has been created.");
    }

    /* soundメソッドの具体的な実装 */
    void sound() {
        System.out.println("Woof Woof!");
    }
}

public class Main {
    public static void main(String[] args) {
        /* Dogクラスのインスタンスを生成 */
        Dog d = new Dog();
        /* Dogクラスのsoundメソッドを呼び出し */
        d.sound();
        /* 出力結果：
        An animal has been created.
        A dog has been created.
        Woof Woof! */
    }
}

